7	------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		use ieee.math_real.all;
14		
15	library work;
16		use work.psi_common_math_pkg.all;
17		use work.psi_ms_daq_pkg.all;
18	
19	library work;
20		use work.psi_tb_txt_util.all;
21		use work.psi_tb_compare_pkg.all;
22	
23	------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------
26	package psi_ms_daq_input_tb_pkg is
27		
28		-- *** Generics Record ***
29		type Generics_t is record
30			StreamWidth_g : positive;
31			VldPulsed_g : boolean;
32		end record;
33		
34		------------------------------------------------------------
35		-- Not exported Generics
36		------------------------------------------------------------
37		constant IntDataWidth_g : positive := 64;
38		constant StreamBuffer_g : positive := 32;
39		constant StreamClkFreq_g : real := 125.0e6;
40		constant StreamTsFifoDepth_g : positive := 8;
41		constant StreamTimeout_g : real := 10.0e-6;
42		constant StreamUseTs_g : boolean := true;
43		
44		-- Handwritten Stuff	
45		constant FrameType_Trigger_c	: string	:= "TRIGGER";
46		constant FrameType_Timeout_c	: string	:= "TIMEOUT";
47		
48		procedure ApplyStrData (			Samples		: in	integer;
49											TrigSpl		: in	integer	:= integer'high;
50											Timestamp	: in	integer;
51											Generics 	: in 	Generics_t;
52									signal 	Str_Clk 	: in 	std_logic;
53									signal 	Str_Vld 	: inout std_logic;
54									signal 	Str_Rdy 	: in 	std_logic;
55									signal 	Str_Data 	: inout std_logic_vector;
56									signal 	Str_Trig 	: inout std_logic;
57									signal	Str_Ts		: inout std_logic_vector;
58											DataOffs	: in	integer := 0);
59										
60		procedure CheckAcqData (			Samples		: in	integer;
61											Timestamp	: in	integer;
62											Generics 	: in 	Generics_t;
63											FrameType	: in	string;
64									signal 	Clk 		: in 	std_logic;
65									signal 	Daq_Vld 	: in 	std_logic;
66									signal 	Daq_Rdy 	: inout std_logic;
67									signal 	Daq_Data 	: in 	Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
68									signal 	Ts_Vld		: in 	std_logic;
69									signal 	Ts_Rdy		: inout std_logic;
70									signal 	Ts_Data		: in 	std_logic_vector;
71											IsBadTs		: in	boolean	:= false;
72											DataOffs	: in	integer := 0);
73										
74	end package;
75	
76	------------------------------------------------------------
77	-- Package Body
78	------------------------------------------------------------
79	package body psi_ms_daq_input_tb_pkg is
80	
81		procedure ApplyStrData (			Samples		: in	integer;
82											TrigSpl		: in	integer	:= integer'high;
83											Timestamp	: in	integer;
84											Generics 	: in Generics_t;
85									signal 	Str_Clk 	: in std_logic;
86									signal 	Str_Vld 	: inout std_logic;
87									signal 	Str_Rdy 	: in std_logic;
88									signal 	Str_Data 	: inout std_logic_vector;
89									signal 	Str_Trig 	: inout std_logic;
90									signal	Str_Ts		: inout std_logic_vector;
91											DataOffs	: in	integer := 0) is
92		begin
93			Str_Trig <= '0';
94			Str_Ts <= std_logic_vector(to_unsigned(0, Str_Ts'length));
95			Str_Vld <= '1';
96			for SplCnt in 0 to Samples-1 loop
97				Str_Vld <= '1';
98				-- Apply Trigger
99				if SplCnt = TrigSpl then
100					Str_Trig <= '1';
101					Str_Ts <= std_logic_vector(to_unsigned(Timestamp, Str_Ts'length));
102				else
103					Str_Trig <= '0';
104					Str_Ts <= std_logic_vector(to_unsigned(0, Str_Ts'length));
105				end if;
106				-- Apply Data
107				Str_Data <= std_logic_vector(to_unsigned(SplCnt+DataOffs, Generics.StreamWidth_g));			
108				wait until rising_edge(Str_Clk);
109				if Generics.VldPulsed_g then
110					Str_Trig <= '0';
111					Str_Vld <= '0';
112					Str_Data <= std_logic_vector(to_unsigned(0, Generics.StreamWidth_g));	
113					wait until rising_edge(Str_Clk);
114				end if;
115			end loop;
116			Str_Vld <= '0';
117			Str_Trig <= '0';
118			Str_Ts <= std_logic_vector(to_unsigned(0, Str_Ts'length));
119		end procedure;
120		
121		procedure CheckAcqData (			Samples		: in	integer;
122											Timestamp	: in	integer;
123											Generics 	: in 	Generics_t;
124											FrameType	: in	string;
125									signal 	Clk 		: in 	std_logic;
126									signal 	Daq_Vld 	: in 	std_logic;
127									signal 	Daq_Rdy 	: inout std_logic;
128									signal 	Daq_Data 	: in 	Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
129									signal 	Ts_Vld		: in 	std_logic;
130									signal 	Ts_Rdy		: inout std_logic;
131									signal 	Ts_Data		: in 	std_logic_vector;
132											IsBadTs		: in	boolean	:= false;
133											DataOffs	: in	integer := 0) is
134			constant Qwords_c			: integer	:= integer(ceil(real(Samples)*real(Generics.StreamWidth_g)/64.0));
135			constant SplPerQw_c			: integer	:= 64/Generics.StreamWidth_g;
136			variable SplCnt_v			: integer 	:= 0;
137			variable SplData_v			: std_logic_vector(Generics.StreamWidth_g-1 downto 0);
138			variable DelayedToTlast_v	: boolean	:= false;	-- It is possible that an empty word (0 bytes) with TLAST is sent at thed end of the frame in case of timeouts
139			constant Wraparound_c		: integer	:= choose(Generics.StreamWidth_g < 32, 2**Generics.StreamWidth_g, integer'high);
140		begin
141			wait until rising_edge(Clk);
142			Daq_Rdy <= '1';
143			for qw in 0 to Qwords_c-1 loop
144				-- Wait for data
145				wait until rising_edge(Clk) and Daq_Vld = '1';
146				-- Check data
147				for spl in 0 to SplPerQw_c-1 loop
148					if SplCnt_v < Samples then
149						SplData_v := Daq_Data.Data((spl+1)*Generics.StreamWidth_g-1 downto spl*Generics.StreamWidth_g);
150						StdlvCompareInt((SplCnt_v+DataOffs) mod Wraparound_c, SplData_v, "received wrong data, sample" & IndexString(SplCnt_v), false);
151						SplCnt_v := SplCnt_v + 1;
152					end if;
153				end loop;
154				-- Check last, bytes
155				if qw = Qwords_c-1 then
156					-- If TLAST is not asserted, we can expect a delayed TLAST because of a timeout
157					if Daq_Data.Last = '0' then
158						DelayedToTlast_v := true;
159					end if;		
160					StdlvCompareInt(Samples*Generics.StreamWidth_g/8-qw*8, Daq_Data.Bytes, "last bytes not correct", false);
161				else
162					StdlCompare(0, Daq_Data.Last, "last asserted unexpectedly, QWORD" & IndexString(qw));
163					StdlvCompareInt(8, Daq_Data.Bytes, "bytes not 8, QWORD" & IndexString(qw), false);
164				end if;
165				-- Check IsTrig
166				if FrameType = FrameType_Trigger_c and qw = Qwords_c-1 then
167					StdlCompare(1, Daq_Data.IsTrig, "IsTrig not asserted, QWORD" & IndexString(qw));
168				else
169					StdlCompare(0, Daq_Data.IsTrig, "IsTrig asserted unexpectedly, QWORD" & IndexString(qw));
170				end if;
171				-- Check IsTo
172				if FrameType = FrameType_Timeout_c and qw = Qwords_c-1 and not DelayedToTlast_v then
173					StdlCompare(1, Daq_Data.IsTo, "IsTo not asserted, QWORD" & IndexString(qw));
174				else
175					StdlCompare(0, Daq_Data.IsTo, "IsTo asserted unexpectedly, QWORD" & IndexString(qw));
176				end if;	
177			end loop;
178			-- Check delayed TLAST
179			if DelayedToTlast_v then
180				wait until rising_edge(Clk) and Daq_Vld = '1';
181				if FrameType = FrameType_Timeout_c then
182					StdlCompare(1, Daq_Data.IsTo, "IsTo not asserted, QWORD" & IndexString(Qwords_c));
183					StdlvCompareInt(0, Daq_Data.Bytes, "delayed TLAST must have zero data bytes", false);
184					StdlCompare(0, Daq_Data.IsTrig, "delayed TLAST must be non-Trigger");
185					StdlCompare(1, Daq_Data.Last, "delayed TLAST must have LAST asserted");
186				else
187					report "###ERROR###: Delayed TLAST is only possible for timeout frames" severity error;
188				end if;
189			end if;
190			Daq_Rdy <= '0';
191					
192			-- Check timestamp
193			if FrameType = FrameType_Trigger_c then
194				if not IsBadTs then
195					StdlCompare(1, Ts_Vld, "Ts_Vld not asserted");
196				end if;
197				StdlvCompareInt(Timestamp, Ts_Data, "Received wrong timestamp", true);
198				Ts_Rdy <= '1';
199				wait until rising_edge(Clk);
200				Ts_Rdy <= '0';
201				wait until rising_edge(Clk);
202			else
203				StdlCompare(0, Ts_Vld, "Ts_Vld asserted unexpectedly for timeout fram");
204			end if;
205				
206		end procedure;
207			
208	end;
