32		use work.psi_ms_daq_input_tb_case_timeout.all;
33		use work.psi_ms_daq_input_tb_case_ts_overflow.all;
34		use work.psi_ms_daq_input_tb_case_trig_in_posttrig.all;
35		use work.psi_ms_daq_input_tb_case_always_trig.all;
36		use work.psi_ms_daq_input_tb_case_backpressure.all;
