38	
39	------------------------------------------------------------
40	-- Entity Declaration
41	------------------------------------------------------------
42	entity psi_ms_daq_input_tb is
43		generic (
44			StreamWidth_g 	: positive	:= 16;
45			VldPulsed_g		: boolean	:= false
46		);
47	end entity;
48	
49	------------------------------------------------------------
50	-- Architecture
51	------------------------------------------------------------
52	architecture sim of psi_ms_daq_input_tb is
53		-- *** Fixed Generics ***
54		constant StreamBuffer_g : positive := 32;
55		constant StreamTimeout_g : real := 10.0e-6;
56		constant StreamClkFreq_g : real := 125.0e6;
57		constant StreamTsFifoDepth_g : positive := 8;
58		constant StreamUseTs_g : boolean := true;
59		
60		-- *** Not Assigned Generics (default values) ***
61		
62		-- *** Exported Generics ***
63		constant Generics_c : Generics_t := (
64			StreamWidth_g 	=> StreamWidth_g,
65			VldPulsed_g		=> VldPulsed_g);
66		
67		-- *** TB Control ***
68		signal TbRunning : boolean := True;
69		signal NextCase : integer := -1;
70		signal ProcessDone : std_logic_vector(0 to 1) := (others => '0');
71		constant AllProcessesDone_c : std_logic_vector(0 to 1) := (others => '1');
72		constant TbProcNr_stream_c : integer := 0;
73		constant TbProcNr_daq_c : integer := 1;
74		
75		-- *** DUT Signals ***
76		signal Str_Clk : std_logic := '1';
77		signal Str_Vld : std_logic := '0';
78		signal Str_Rdy : std_logic := '0';
79		signal Str_Data : std_logic_vector(StreamWidth_g-1 downto 0) := (others => '0');
80		signal Str_Trig : std_logic := '0';
81		signal Str_Ts : std_logic_vector(63 downto 0) := (others => '0');
82		signal ClkReg : std_logic := '1';
83		signal RstReg : std_logic := '1';
84		signal ClkMem : std_logic := '1';
85		signal RstMem : std_logic := '1';
86		signal PostTrigSpls : std_logic_vector(31 downto 0) := (others => '0');
87		signal Mode : RecMode_t := (others => '0');
88		signal Arm : std_logic := '0';
89		signal IsArmed : std_logic := '0';
90		signal IsRecording : std_logic := '0';
91		signal ToDisable : std_logic := '0';
92		signal FrameTo : std_logic := '0';
93		signal Daq_Vld : std_logic := '0';
94		signal Daq_Rdy : std_logic := '0';
95		signal Daq_Data : Input2Daq_Data_t(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
96		signal Daq_Level : std_logic_vector(15 downto 0) := (others => '0');
97		signal Daq_HasLast : std_logic := '0';
98		signal Ts_Vld : std_logic := '0';
99		signal Ts_Rdy : std_logic := '0';
100		signal Ts_Data : std_logic_vector(63 downto 0) := (others => '0');
101		
