40			signal Inp_Level : inout t_aslv16;
41			signal Ts_Vld : inout std_logic_vector;
42			signal Ts_Rdy : in std_logic_vector;
43			signal Ts_Data : inout t_aslv64;
44			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
45			signal Dma_Cmd_Vld : in std_logic;
46			constant Generics_c : Generics_t);
47			
