77	------------------------------------------------------------
78	package body psi_ms_daq_daq_sm_tb_case_irq is
79		procedure control (
80			signal Clk : in std_logic;
81			signal Rst : inout std_logic;
82			signal GlbEna : inout std_logic;
83			signal StrEna : inout std_logic_vector;
84			signal StrIrq : in std_logic_vector;
85			signal Inp_HasLast : inout std_logic_vector;
86			signal Inp_Level : inout t_aslv16;
87			signal Ts_Vld : inout std_logic_vector;
88			signal Ts_Rdy : in std_logic_vector;
89			signal Ts_Data : inout t_aslv64;
90			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
91			signal Dma_Cmd_Vld : in std_logic;
92			constant Generics_c : Generics_t) is
93		begin
94			print(">> -- irq --");	
95			
96			-- Normal Order
97			print(">> Normal Order");
98			InitTestCase(Clk, Rst);
99			TestCase := 0;
100			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
101			Inp_Level(0) <= LvlThreshold_c;		
102			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
103			Inp_Level(0) <= (others => '0');
104			ControlWaitCompl(Clk);			
105			
106			-- Flipped Order
107			print(">> Flipped Order");
108			InitTestCase(Clk, Rst);
109			TestCase := 1;
110			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
111			Inp_Level(0) <= LvlThreshold_c;		
112			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
113			Inp_Level(0) <= (others => '0');
114			ControlWaitCompl(Clk);			
115			
116			-- IRQ FIFO full
117			-- ... FIFO is full after Streams (4) x 3 = 12 open transfers
118			print(">> IRQ FIFO full");
119			InitTestCase(Clk, Rst);
120			TestCase := 2;
121			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
122			Inp_Level(0) <= LvlThreshold_c;	
123			-- Fill FIFO
124			for i in 0 to 11 loop
125				wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
126			end loop;
127			-- Checked transfer
128			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
129			Inp_Level(0) <= (others => '0');
130			ControlWaitCompl(Clk);		
131	
132			-- Multi-Stream
133			wait for 1 us;
134			print(">> Multi-Stream");
135			InitTestCase(Clk, Rst);
136			TestCase := 3;
137			ConfigureAuto(	WinSize => 4096, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
138			for i in 3 downto 0 loop
139				Inp_Level(i) <= LvlThreshold_c;	
140				wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';			
141				Inp_Level(i) <= (others => '0');
142				wait for 200 ns;
143			end loop;
144			ControlWaitCompl(Clk);			
145			
146			-- Win-Change without trigger
147			wait for 1 us;
148			print(">> Win-Change without trigger");
149			InitTestCase(Clk, Rst);
150			TestCase := 4;
151			ConfigureAuto(	WinSize => 4096*2, Ringbuf => '0', Overwrite => '1', Wincnt => 2, Wincur => 0);	
152			Inp_Level(0) <= LvlThreshold_c;		
153			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
154			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
155			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
156			Inp_Level(0) <= (others => '0');
157			ControlWaitCompl(Clk);	
158	
159			-- No IRQ on Ringbuf Wrap
160			print(">> No IRQ on Ringbuf Wrap");
161			InitTestCase(Clk, Rst);
162			TestCase := 5;
163			ConfigureAuto(	WinSize => 4096*2, Ringbuf => '1', Overwrite => '1', Wincnt => 2, Wincur => 0);	
164			Inp_Level(0) <= LvlThreshold_c;		
165			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
166			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
167			wait until rising_edge(Clk) and Dma_Cmd_Vld = '1';
168			Inp_Level(0) <= (others => '0');
169			ControlWaitCompl(Clk);		
170			
171		end procedure;
172		
173		procedure dma_cmd (
174			signal Clk : in std_logic;
175			signal StrIrq : in std_logic_vector;
176			signal Dma_Cmd : in DaqSm2DaqDma_Cmd_t;
177			signal Dma_Cmd_Vld : in std_logic;
178			constant Generics_c : Generics_t) is
179		begin
180			-- Normal Order
181			WaitForCase(0,  Clk);
182			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr0.0",
183								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
184			ProcDone(2)	:= '1';			
185			
186			-- Flipped Order
187			WaitForCase(1,  Clk);
188			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr0.0",
189								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
190			ProcDone(2)	:= '1';			
191			
192			-- IRQ FIFO full
193			WaitForCase(2,  Clk);
194			-- Fill FIFO
195			for i in 0 to 11 loop
196				ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr" & to_string(i), NextWin => true,
197									Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
198			end loop;
199			-- Checked transfer
200			CheckNoActivity(Dma_Cmd_Vld, 1 us, 0, "Full");
201			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, ExeSize=> 512, Msg => "Wr12", NextWin => true,
202								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);
203			ProcDone(2)	:= '1';	
204			
205			-- Multi-Stream
206			WaitForCase(3,  Clk);
207			for i in 3 downto 0 loop
208				ExpectDmaCmdAuto(	Stream	=> i, MaxSize => 4096, ExeSize=> 512*(i+1), Msg => "Wr" & to_string(i), NextWin => true,
209									Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);		
210			end loop;
211			ProcDone(2)	:= '1';	
212			
213			-- Win-Change without trigger
214			WaitForCase(4,  Clk);
215			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
216								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
217			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0", NextWin => true,
218								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
219			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
220								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);								
221			ProcDone(2)	:= '1';	
222			
223			-- No IRQ on Ringbuf Wrap
224			WaitForCase(5,  Clk);
225			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
226								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
227			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0", 
228								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);	
229			ExpectDmaCmdAuto(	Stream	=> 0, MaxSize => 4096, Msg => "Wr0",
230								Clk	=> Clk,	Dma_Cmd	=> Dma_Cmd,	Dma_Vld	=> Dma_Cmd_Vld);								
231			ProcDone(2)	:= '1';			
232			
233		end procedure;
234		
235		procedure dma_resp (
236			signal Clk : in std_logic;
237			signal StrIrq : in std_logic_vector;
238			signal Dma_Resp : inout DaqDma2DaqSm_Resp_t;
239			signal Dma_Resp_Vld : inout std_logic;
240			signal Dma_Resp_Rdy : in std_logic;
241			signal TfDone : inout std_logic;
242			signal StrLastWin : in WinType_a(Streams_g-1 downto 0);
243			constant Generics_c : Generics_t) is
244		begin
245			-- Normal Order
246			WaitForCase(0,  Clk);
247			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
248								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
249			wait for 200 ns;
250			StdlvCompareStdlv ("0000", StrIrq, "IRQs asserted unexpectedly");
251			assert StrIrq'last_event > 200 ns report "###ERROR###: IRQs not idle" severity error;
252			AssertTfDone(Clk, TfDone);
253			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);	
254			ProcDone(1)	:= '1';	
255			
256			-- Flipped Order
257			WaitForCase(1,  Clk);
258			AssertTfDone(Clk, TfDone);
259			wait for 200 ns;
260			StdlvCompareStdlv ("0000", StrIrq, "IRQs asserted unexpectedly");
261			assert StrIrq'last_event > 200 ns report "###ERROR###: IRQs not idle" severity error;
262			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
263								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
264			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
265			ProcDone(1)	:= '1';			
266			
267			-- IRQ FIFO full
268			WaitForCase(2,  Clk);
269			-- Fill FIFO
270			for i in 0 to 11 loop
271				ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
272									Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
273			end loop;
274			-- Wait
275			wait for 1.1 us;
276			-- Send IRQs
277			for i in 0 to 11 loop
278				AssertTfDone(Clk, TfDone);
279				CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => i mod 3, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
280			end loop;
281			-- Last transfer
282			ApplyDmaRespAuto(	Stream => 0, Trigger => '1',
283								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
284			AssertTfDone(Clk, TfDone);
285			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);			
286			ProcDone(1)	:= '1';	
287			
288			-- Multi-Stream
289			WaitForCase(3,  Clk);
290			for i in 3 downto 0 loop
291				ApplyDmaRespAuto(	Stream => i, Trigger => '1',
292									Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
293			end loop;
294			for i in 3 downto 0 loop
295				AssertTfDone(Clk, TfDone);
296				CheckIrq(MaxWait => (1 us), Stream => i, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);	
297			end loop;		
298			ProcDone(1)	:= '1';	
299			
300			-- Win-Change without trigger
301			WaitForCase(4,  Clk);
302			wait for 100 ns;
303			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
304								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
305			AssertTfDone(Clk, TfDone);
306			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Before Window Change");
307			wait for 100 ns;
308			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
309								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
310			AssertTfDone(Clk, TfDone);
311			CheckIrq(MaxWait => (1 us), Stream => 0, LastWin => 0, Clk => Clk, StrIrq => StrIrq, StrLastWin => StrLastWin);		
312			wait for 100 ns;
313			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
314								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);
315			AssertTfDone(Clk, TfDone);
316			CheckNoActivityStlv(StrIrq, 100 ns, 0, "After Window Change");
317			ProcDone(1)	:= '1';	
318			
319			-- No IRQ on Ringbuf Wrap
320			WaitForCase(5,  Clk);
321			wait for 100 ns;
322			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
323								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);		
324			AssertTfDone(Clk, TfDone);
325			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Before Wrap");
326			wait for 100 ns;
327			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
328								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);	
329			AssertTfDone(Clk, TfDone);
330			CheckNoActivityStlv(StrIrq, 100 ns, 0, "Wrap");
331			wait for 100 ns;
332			ApplyDmaRespAuto(	Stream => 0, Trigger => '0',
333								Clk	=> Clk,	Dma_Resp => Dma_Resp, Dma_Resp_Vld => Dma_Resp_Vld,	Dma_Resp_Rdy => Dma_Resp_Rdy);
334			AssertTfDone(Clk, TfDone);
335			CheckNoActivityStlv(StrIrq, 100 ns, 0, "After Wrap");
336			ProcDone(1)	:= '1';			
337			
338		end procedure;
339		
340		procedure ctx (
341			signal Clk : in std_logic;
342			signal CtxStr_Cmd : in ToCtxStr_t;
343			signal CtxStr_Resp : inout FromCtx_t;
344			signal CtxWin_Cmd : in ToCtxWin_t;
345			signal CtxWin_Resp : inout FromCtx_t;
346			constant Generics_c : Generics_t) is
347		begin
348			-- Normal Order
349			WaitForCase(0, Clk);
350			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", NextWin => true, IsTrig => true,
351									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);								
352			ProcDone(0)	:= '1';			
353			
354			-- Flipped Order
355			WaitForCase(1, Clk);
356			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", NextWin => true, IsTrig => true,
357									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);								
358			ProcDone(0)	:= '1';			
359			
360			-- IRQ FIFO full
361			WaitForCase(2, Clk);
362			for i in 0 to 11 loop
363				ExpCtxFullBurstAuto(	Stream => 0, NextWin => true, IsTrig => true,
364									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
365			end loop;
366			ExpCtxFullBurstAuto(	Stream => 0, NextWin => true, IsTrig => true,
367									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
368			ProcDone(0)	:= '1';
369			
370			-- Multi-Stream
371			WaitForCase(3, Clk);
372			for i in 3 downto 0 loop
373				ExpCtxFullBurstAuto(	Stream => i, NextWin => true, IsTrig => true,
374										Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);	
375			end loop;
376			ProcDone(0)	:= '1';			
377			
378			-- Win-Change without trigger
379			WaitForCase(4, Clk);
380			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", 
381									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
382			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.1", NextWin => true,
383									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
384			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr1.0",
385									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);								
386			ProcDone(0)	:= '1';	
387			
388			-- No IRQ on Ringbuf Wrap
389			WaitForCase(5, Clk);
390			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.0", 
391									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
392			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.1", 
393									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);
394			ExpCtxFullBurstAuto(	Stream => 0, Msg => "Wr0.2",
395									Clk => Clk, CtxStr_Cmd => CtxStr_Cmd, CtxStr_Resp => CtxStr_Resp, CtxWin_Cmd => CtxWin_Cmd, CtxWin_Resp => CtxWin_Resp);								
396			ProcDone(0)	:= '1';			
397			
398		end procedure;
399		
400	end;
