23	------------------------------------------------------------
24	-- Package Header
25	------------------------------------------------------------
26	package psi_ms_daq_daq_sm_tb_pkg is
27		
28		-- *** Generics Record ***
29		type Generics_t is record
30			Dummy : boolean; -- required since empty records are not allowed
31		end record;
32		
33		------------------------------------------------------------
34		-- Not exported Generics
35		------------------------------------------------------------
36		constant MaxBurstSize_g : positive := 512;
37		constant StreamPrio_g : t_ainteger := (1, 2, 3, 1);
38		constant StreamWidth_g : t_ainteger := (8, 16, 32, 64);
