273		procedure InitTestCase(	signal	Clk			: in	std_logic;
274								signal	Rst			: out	std_logic) is
275		begin
276			ConfigureAuto;
277			ProcDone := (others => '0');	
278			TestCase := -1;
279			DmaCmdOpen := 0;
280			PtrStr_v := BufStart_c;
281			PtrDma_v := BufStart_c;
282			SplsWinStr_v := (others => (others => 0));
283			wait until rising_edge(Clk);
284			Rst <= '1';
285			wait until rising_edge(Clk);
286			wait until rising_edge(Clk);
287			Rst <= '0';
288			wait until rising_edge(Clk);
289		end procedure;
290		
291		procedure FinishTestCase is
292		begin
293			TestCase := -1;
294			wait for 1 us;
295		end procedure;
296		
297		procedure ControlWaitCompl(	signal	Clk			: in	std_logic) is
298		begin
299			while ProcDone /= AllDone loop
300				wait until rising_edge(Clk);
301			end loop;
302			ProcDone := (others => '0');		
303		end procedure;	
304	
305		procedure WaitForCase(			SubCase		: in	integer;
306								signal	Clk			: in	std_logic) is
307		begin
308			while TestCase /= SubCase loop
309				wait until rising_edge(Clk);
310			end loop;
311		end procedure;
