314		procedure ExpCtxRead(			Stream 		: in	integer;
315										BufStart 	: in 	integer		:= 16#01230000#;
316										WinSize		: in	integer		:= 16#00100000#;
317										Ptr			: in	integer		:= 16#01238000#;
318										Ringbuf		: in	std_logic	:= '0';
319										Overwrite	: in	std_logic	:= '0';
320										Wincnt		: in	integer		:= 2;
321										Wincur		: in	integer		:= 0;
322										WinSel		: in	integer		:= -1;
323										SamplesWin	: in 	integer;
324										WinIsTrig	: in	boolean		:= false;
325								signal 	Clk			: in	std_logic;
326								signal 	CtxStr_Cmd	: in	ToCtxStr_t;
327								signal 	CtxStr_Resp	: out	FromCtx_t;
328								signal 	CtxWin_Cmd	: in	ToCtxWin_t;
329								signal 	CtxWin_Resp : out	FromCtx_t;
330										Msg			: in	string		:= "") is
331			variable WindowSel_v : integer;
332		begin
333			if WinSel = -1 then
334				WindowSel_v := Wincur;
335			else
336				WindowSel_v := WinSel;
337			end if;
338			for acc in 0 to 3 loop	-- 3 read accesses are expected for stream context, 1 for window context
339				wait until rising_edge(Clk) and ((CtxStr_Cmd.Rd = '1') or (CtxWin_Cmd.Rd = '1'));
340				CtxStr_Resp.RdatLo <= (others => '0');
341				CtxStr_Resp.RdatHi <= (others => '0');
342				if CtxStr_Cmd.Rd = '1' then
343					IntCompare(Stream, CtxStr_Cmd.Stream, "ApplyContext.Str: Wrong stream number - " & Msg);
344					StdlCompare(0, CtxStr_Cmd.WenLo, "ApplyContext.Str: WenLo asserted - " & Msg);
345					StdlCompare(0, CtxStr_Cmd.WenHi, "ApplyContext.Str: WenHi asserted - " & Msg);
346					case CtxStr_Cmd.Sel is
347						when CtxStr_Sel_ScfgBufstart_c =>	CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_RINGBUF_c) 	<= Ringbuf;
348															CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_OVERWRITE_c) <= Overwrite;
349															CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_WINCNT_c+7 downto CtxStr_Sft_SCFG_WINCNT_c) <= std_logic_vector(to_unsigned(Wincnt, 8));
350															CtxStr_Resp.RdatLo(CtxStr_Sft_SCFG_WINCUR_c+7 downto CtxStr_Sft_SCFG_WINCUR_c) <= std_logic_vector(to_unsigned(Wincur, 8));
351															CtxStr_Resp.RdatHi <= std_logic_vector(to_unsigned(BufStart, 32));
352						when CtxStr_Sel_WinsizePtr_c =>		CtxStr_Resp.RdatLo <= std_logic_vector(to_unsigned(WinSize, 32));
353															CtxStr_Resp.RdatHi <= std_logic_vector(to_unsigned(Ptr, 32));
354						when CtxStr_Sel_Winend_c =>			CtxStr_Resp.RdatLo <= std_logic_vector(to_unsigned(BufStart+WinSize*(Wincur+1), 32));
355						when others => report "###ERROR###: ApplyContext.Str: illegal CtxStr_Cmd.Sel - " & Msg severity error;
356					end case;
357				elsif CtxWin_Cmd.Rd = '1' then
358					IntCompare(Stream, CtxWin_Cmd.Stream, "ApplyContext.Win: Wrong stream number - " & Msg);
359					IntCompare(WindowSel_v, CtxWin_Cmd.Window, "ApplyContext.Win: Wrong window number - " & Msg);
360					StdlCompare(0, CtxWin_Cmd.WenLo, "ApplyContext.Win: WenLo asserted - " & Msg);
361					StdlCompare(0, CtxWin_Cmd.WenHi, "ApplyContext.Win: WenHi asserted - " & Msg);		
362					case CtxWin_Cmd.Sel is
363						when CtxWin_Sel_WincntWinlast_c =>	CtxWin_Resp.RdatLo(30 downto 0) <= std_logic_vector(to_unsigned(SamplesWin, 31));
364															if WinIsTrig then
365																CtxWin_Resp.RdatLo(31) <= '1';
366															else
367																CtxWin_Resp.RdatLo(31) <= '0';
368															end if;
369						when others => report "###ERROR###: ApplyContext.Win: illegal CtxStr_Cmd.Sel - " & Msg severity error;
370					end case;					
371				end if;
372			end loop;
373		end procedure;
374			
375		procedure ExpCtxWrite(			Stream		: in	integer;
376										BufStart 	: in 	integer		:= 16#01230000#;
377										WinSize		: in	integer		:= 16#00100000#;
378										Ptr			: in	integer		:= 16#01238000#;
379										Ringbuf		: in	std_logic	:= '0';
380										Overwrite	: in	std_logic	:= '0';
381										Wincnt		: in	integer		:= 2;
382										Wincur		: in	integer		:= 0;
383										WinNext		: in	integer		:= -1;
384										SamplesWin	: in 	integer;
385										WinIsTrig	: in	boolean		:= false;
386										WinLast		: in	integer;
387										WriteTs		: in	CheckTs_t	:= DontCheck;
388										Timstamp	: in	std_logic_vector(63 downto 0)	:= (others => 'X');
389								signal 	Clk			: in	std_logic;
390								signal 	CtxStr_Cmd	: in	ToCtxStr_t;
391								signal 	CtxWin_Cmd	: in	ToCtxWin_t;
392										Msg			: in	string		:= "") is
393										
394			variable WinNext_v : integer;
395		begin
396			-- No window change by default
397			if WinNext = -1 then
398				WinNext_v := Wincur;
399			else
400				WinNext_v := WinNext;
401			end if;
402			wait until rising_edge(Clk) and CtxStr_Cmd.WenLo = '1';
403			-- Stream
404			IntCompare(Stream, CtxStr_Cmd.Stream, "ExpectContext.Str: Wrong stream number 0 - " & Msg);
405			StdlvCompareStdlv(CtxStr_Sel_ScfgBufstart_c, CtxStr_Cmd.Sel, "ExpectContext.Str: Wrong Sel (unexpected sequence 0) - " & Msg);
406			StdlCompare(0, CtxStr_Cmd.WenHi, "ExpectContext.Str: WenHi asserted in first cycle (BufStart overwritten) - " & Msg);
407			StdlCompare(choose(Ringbuf='1',1,0), CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_RINGBUF_c), "ExpectContext.Str: Wrong RINGBUFFER - " & Msg);
408			StdlCompare(choose(Overwrite='1',1,0), CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_OVERWRITE_c), "ExpectContext.Str: Wrong OVERWRITE - " & Msg);
409			StdlvCompareInt(Wincnt, CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_WINCNT_c+7 downto CtxStr_Sft_SCFG_WINCNT_c), "ExpectContext.Str: Wrong SCFG_WINCNT - " & Msg);
410			StdlvCompareInt(WinNext_v, CtxStr_Cmd.WdatLo(CtxStr_Sft_SCFG_WINCUR_c+7 downto CtxStr_Sft_SCFG_WINCUR_c), "ExpectContext.Str: Wrong SCFG_WINCUR - " & Msg);
411			-- Window
412			IntCompare(Stream, CtxWin_Cmd.Stream, "ExpectContext.Win: Wrong stream number 0 - " & Msg);
413			IntCompare(Wincur, CtxWin_Cmd.Window, "ExpectContext.Win: Wrong Window number 0 - " & Msg);
414			StdlCompare(1, CtxWin_Cmd.WenLo, "ExpectContext.Win: WenLo not asserted in first cycle - " & Msg);
415			StdlCompare(1, CtxWin_Cmd.WenHi, "ExpectContext.Win: WenHi not asserted in first cycle - " & Msg);
416			StdlvCompareInt(SamplesWin, CtxWin_Cmd.WdatLo(30 downto 0), "ExpectContext.Win: Wrong WIN_WINCNT - " & Msg);
417			StdlCompare(Choose(WinIsTrig, 1, 0), CtxWin_Cmd.WdatLo(31), "ExpectContext.Win Wrong WIN_ISTRIG - " & Msg);
418			StdlvCompareInt(WinLast, CtxWin_Cmd.WdatHi, "ExpectContext.Str: Wrong WIN_WINLAST - " & Msg);
419			wait until rising_edge(Clk) and CtxStr_Cmd.WenHi = '1';
420			
421			-- Stream
422			IntCompare(Stream, CtxStr_Cmd.Stream, "ExpectContext.Str: Wrong stream number 1 - " & Msg);
423			StdlvCompareStdlv(CtxStr_Sel_WinsizePtr_c, CtxStr_Cmd.Sel, "ExpectContext.Str: Wrong Sel (unexpected sequence 1) - " & Msg);
424			StdlCompare(0, CtxStr_Cmd.WenLo, "ExpectContext.Str: WenLo asserted in second cycle (WinSize overwritten) - " & Msg);
425			StdlvCompareInt(Ptr, CtxStr_Cmd.WdatHi, "ExpectContext.Str: Wrong PTR - " & Msg);		
426			-- Window
427			if WriteTs = CheckWritten then
428				IntCompare(Stream, CtxWin_Cmd.Stream, "ExpectContext.Win: Wrong stream number 1 - " & Msg);
429				IntCompare(Wincur, CtxWin_Cmd.Window, "ExpectContext.Win: Wrong Window number 1 - " & Msg);
430				StdlCompare(1, CtxWin_Cmd.WenLo, "ExpectContext.Win: WenLo not asserted in scond cycle - " & Msg);
431				StdlCompare(1, CtxWin_Cmd.WenHi, "ExpectContext.Win: WenHi not asserted in second cycle - " & Msg);
432				StdlvCompareStdlv(Timstamp(31 downto 0), CtxWin_Cmd.WdatLo, "ExpectContext.Str: Wrong TS-LO - " & Msg);
433				StdlvCompareStdlv(Timstamp(63 downto 32), CtxWin_Cmd.WdatHi, "ExpectContext.Str: Wrong TS-HI - " & Msg);
434			elsif WriteTs = CheckNotWritten then
435				StdlCompare(0, CtxWin_Cmd.WenLo, "ExpectContext.Win: WenLo asserted in scond cycle (without TS) - " & Msg);
436				StdlCompare(0, CtxWin_Cmd.WenHi, "ExpectContext.Win: WenHi asserted in scond cycle (without TS) - " & Msg);
437			end if;
438			wait until rising_edge(Clk) and CtxStr_Cmd.WenLo = '1';
439			
440			-- Stream
441			IntCompare(Stream, CtxStr_Cmd.Stream, "ExpectContext.Str: Wrong stream number 2 - " & Msg);
442			StdlvCompareStdlv(CtxStr_Sel_Winend_c, CtxStr_Cmd.Sel, "ExpectContext.Str: Wrong Sel (unexpected sequence 2) - " & Msg);
443			StdlCompare(0, CtxStr_Cmd.WenHi, "ExpectContext.Str: WenHi asserted in third cycle (Unused overwritten) - " & Msg);
444			StdlvCompareInt(BufStart+WinSize*(WinNext_v+1), CtxStr_Cmd.WdatLo, "ExpectContext.Str: Wrong WINEND - " & Msg);		
445		end procedure;
446		
447		procedure ExpCtxUpdate(				Stream				: in	integer;
448											TfSize				: in	integer;	-- in bytes
449											NextWin				: in	boolean		:= false;
450											IsTrig				: in	boolean		:= false;
451											BufStart 			: in 	integer		:= 16#01230000#;
452											WinSize				: in	integer		:= 16#00100000#;
453											PtrBefore			: in	integer		:= 16#01238000#;
454											Ringbuf				: in	std_logic	:= '0';
455											Overwrite			: in	std_logic	:= '0';
456											Wincnt				: in	integer		:= 2;
457											Wincur				: in	integer		:= 0;
458											SamplesWinBefore	: in 	integer;
459											WriteTs				: in	CheckTs_t	:= DontCheck;
460											Timstamp			: in	std_logic_vector(63 downto 0)	:= (others => 'X');
461								variable	PtrAfter			: out	integer;
462								signal 		Clk					: in	std_logic;
463								signal 		CtxStr_Cmd			: in	ToCtxStr_t;
464								signal 		CtxStr_Resp			: out	FromCtx_t;
465								signal 		CtxWin_Cmd			: in	ToCtxWin_t;
466								signal 		CtxWin_Resp			: out	FromCtx_t;
467											Msg					: in	string		:= "") is
468			variable PtrAfter_v 		: integer;
469			variable SampleswinAfter_v	: integer;
470			variable WinLastAfter_v		: integer;
471			constant StrWidthBytes_c	: integer	:= StreamWidth_g(Stream)/8;
472			variable WinAfter_v			: integer;
473		begin
474			-- Calculations
475			PtrAfter_v := PtrBefore + TfSize;
476			SampleswinAfter_v := SamplesWinBefore + TfSize/StrWidthBytes_c;
477			if SampleswinAfter_v > WinSize/StrWidthBytes_c then
478				SampleswinAfter_v := WinSize/StrWidthBytes_c;
479			end if;
480			WinLastAfter_v := PtrBefore + TfSize - StrWidthBytes_c;
481			if NextWin then
482				if Wincur = Wincnt then
483					WinAfter_v := 0;
484				else
485					WinAfter_v := Wincur + 1;
486				end if;
487				PtrAfter_v	:= BufStart+WinAfter_v*WinSize;
488			else
489				WinAfter_v := Wincur;
490				-- wraparound for ringbuffer
491				if Ringbuf = '1' then
492					if PtrAfter_v >= BufStart + (Wincur+1)*WinSize then
493						PtrAfter_v := PtrAfter_v - WinSize;
494					end if;
495				end if;
496			end if;
497			
498			-- Read
499			ExpCtxRead(	Stream 		=> Stream,
500						BufStart 	=> BufStart,
501						WinSize		=> WinSize,
502						Ptr			=> PtrBefore,
503						Ringbuf		=> Ringbuf,
504						Overwrite	=> Overwrite,
505						Wincnt		=> Wincnt,
506						Wincur		=> Wincur,
507						SamplesWin	=> SamplesWinBefore,
508						Clk			=> Clk,
509						CtxStr_Cmd	=> CtxStr_Cmd,
510						CtxStr_Resp	=> CtxStr_Resp,
511						CtxWin_Cmd	=> CtxWin_Cmd,
512						CtxWin_Resp => CtxWin_Resp,
513						Msg			=> Msg);
514			-- Write
515			ExpCtxWrite(Stream		=> Stream,
516						BufStart 	=> BufStart,
517						WinSize		=> WinSize,
518						Ptr			=> PtrAfter_v,
519						Ringbuf		=> Ringbuf,
520						Overwrite	=> Overwrite,
521						Wincnt		=> Wincnt,
522						Wincur		=> Wincur,
523						WinNext		=> WinAfter_v,
524						SamplesWin	=> SampleswinAfter_v,
525						WinIsTrig	=> IsTrig,
526						WinLast		=> WinLastAfter_v,
527						WriteTs		=> WriteTs,
528						Timstamp	=> Timstamp,
529						Clk			=> Clk,
530						CtxStr_Cmd	=> CtxStr_Cmd,
531						CtxWin_Cmd	=> CtxWin_Cmd,
532						Msg			=> Msg);
533			-- Output Values
534			PtrAfter := PtrAfter_v;
535		end procedure;
536		
537		procedure ExpCtxFullBurst(			Stream				: in	integer;
538											TfSize				: in	integer;	-- in bytes
539											NextWin				: in	boolean		:= false;
540											BufStart 			: in 	integer		:= 16#01230000#;
541											WinSize				: in	integer		:= 16#00100000#;
542											PtrBefore			: in	integer		:= 16#01238000#;
543											Ringbuf				: in	std_logic	:= '0';
544											Overwrite			: in	std_logic	:= '0';
545											Wincnt				: in	integer		:= 2;
546											Wincur				: in	integer		:= 0;
547											SamplesWinBefore	: in 	integer;
548											WriteTs				: in	CheckTs_t	:= DontCheck;
549											Timstamp			: in	std_logic_vector(63 downto 0)	:= (others => 'X');
550								variable	PtrAfter			: out	integer;
551								signal 		Clk					: in	std_logic;
552								signal 		CtxStr_Cmd			: in	ToCtxStr_t;
553								signal 		CtxStr_Resp			: out	FromCtx_t;
554								signal 		CtxWin_Cmd			: in	ToCtxWin_t;
555								signal 		CtxWin_Resp			: out	FromCtx_t;
556											Msg					: in	string		:= "") is
557		begin
558			-- context read
559			ExpCtxRead(	Stream 		=> Stream,
560						BufStart 	=> BufStart,
561						WinSize		=> WinSize,
562						Ptr			=> PtrBefore,
563						Ringbuf		=> Ringbuf,
564						Overwrite	=> Overwrite,
565						Wincnt		=> Wincnt,
566						Wincur		=> Wincur,
567						SamplesWin	=> SamplesWinBefore,
568						Clk			=> Clk,
569						CtxStr_Cmd	=> CtxStr_Cmd,
570						CtxStr_Resp	=> CtxStr_Resp,
571						CtxWin_Cmd	=> CtxWin_Cmd,
572						CtxWin_Resp => CtxWin_Resp,
573						Msg			=> Msg);
574			-- context update
575			ExpCtxUpdate(	Stream				=> Stream,
576							TfSize				=> TfSize,
577							NextWin				=> NextWin,
578							BufStart 			=> BufStart,
579							WinSize				=> WinSize,
580							PtrBefore			=> PtrBefore,
581							Ringbuf				=> Ringbuf,
582							Overwrite			=> Overwrite,
583							Wincnt				=> Wincnt,
584							Wincur				=> Wincur,
585							SamplesWinBefore	=> SamplesWinBefore,
586							WriteTs				=> WriteTs,
587							Timstamp			=> Timstamp,
588							PtrAfter			=> PtrAfter,
589							Clk					=> Clk,
590							CtxStr_Cmd			=> CtxStr_Cmd,
591							CtxStr_Resp			=> CtxStr_Resp,
592							CtxWin_Cmd			=> CtxWin_Cmd,
593							CtxWin_Resp 		=> CtxWin_Resp,
594							Msg					=> Msg);
595		end procedure;
596			
597		procedure ExpectDmaCmd(			Stream	: in 	integer;
598										Address	: in 	integer;
599										MaxSize	: in 	integer;
600								signal 	Clk		: in	std_logic;
601								signal 	Dma_Cmd	: in	DaqSm2DaqDma_Cmd_t;
602								signal 	Dma_Vld	: in	std_logic;
603										Msg		: in 	string		:= "") is
604		begin
605			wait until rising_edge(Clk) and Dma_Vld = '1';
606			IntCompare(Stream, Dma_Cmd.Stream, "ExpectDmaCmd: Wrong stream number - " & Msg);
607			StdlvCompareInt (Address, Dma_Cmd.Address, "ExpectDmaCmd: Wrong address - " & Msg);
608			StdlvCompareInt (MaxSize, Dma_Cmd.MaxSize, "ExpectDmaCmd: Wrong MaxSize - " & Msg);
609			wait until rising_edge(Clk);
610			StdlCompare(0, Dma_Vld, "ExpectDmaCmd: Vld asserted for more than one cycle - " & Msg);
611			DmaCmdOpen := DmaCmdOpen + 1;	
612		end procedure;
613		
614		procedure ApplyDmaResp(			Stream 			: in	integer;
615										Size 			: in	integer;
616										Trigger			: in	std_logic;
617										Delay			: in	time		:= 0 ns;
618								signal	Clk				: in	std_logic;
619								signal  Dma_Resp		: out	DaqDma2DaqSm_Resp_t;
620								signal  Dma_Resp_Vld	: out	std_logic;
621								signal  Dma_Resp_Rdy	: in	std_logic;
622										Msg				: in	string		:= "") is
623		begin
624			while DmaCmdOpen = 0 loop
625				wait until rising_edge(Clk);
626			end loop;		
627			wait for Delay;
628			-- Send response
629			wait until rising_edge(Clk);	
630			Dma_Resp_Vld 		<= '1';
631			Dma_Resp.Stream 	<= Stream;
632			Dma_Resp.Size 		<= std_logic_vector(to_unsigned(Size, Dma_Resp.Size'length));
633			Dma_Resp.Trigger	<= Trigger;
634			wait until rising_edge(Clk) and Dma_Resp_Rdy = '1';
635			Dma_Resp_Vld 		<= '0';
636			Dma_Resp.Stream		<= 0;
637			Dma_Resp.Trigger	<= 'U';
638			Dma_Resp.Size		<= (others => 'U');
639			DmaCmdOpen := DmaCmdOpen - 1;	
640		end procedure;
641		
642		procedure AssertTfDone(	signal	Clk			: in	std_logic;
643								signal 	TfDone		: out	std_logic) is
644		begin
645			wait until rising_edge(Clk);
646			TfDone <= '1';
647			wait until rising_edge(Clk);
648			TfDone <= '0';
649		end procedure;
650		
651		procedure CheckIrq(			MaxWait			: in	time	:= 1 us;	-- Maximum time to wait for the IRQ
652									Stream			: in	integer;
653									LastWin			: in	integer;
654									Msg				: in	string	:= "";
655							signal	Clk				: in	std_logic;
656							signal	StrIrq			: in	std_logic_vector(3 downto 0);
657							signal	StrLastWin		: in	WinType_a(3 downto 0)) is
658			variable IrqMask_v	: std_logic_vector(StrIrq'range);
659			variable IdleTimePrior_v	: time;
660			variable ProcStartTime_v	: time;
661		begin
662			ProcStartTime_v := now;
663			IrqMask_v := (others => '0');
664			IrqMask_v(Stream) := '1';
665			wait until rising_edge(Clk);
666			wait until (StrIrq = IrqMask_v) and  rising_edge(Clk) for MaxWait;
667			StdlvCompareInt (LastWin, StrLastWin(Stream), "Received wrong LastWin with IRQ - " & Msg);
668			StdlvCompareStdlv (IrqMask_v, StrIrq, "IRQ was not asserted - " & Msg);
669			wait until rising_edge(Clk);
670			StdlvCompareInt (0, StrIrq, "IRQ was not deasserted - " & Msg);	
671		end procedure;
672		
673		procedure ExpCtxReadAuto(		Stream		: in	integer;
674								signal 	Clk			: in	std_logic;
675								signal 	CtxStr_Cmd	: in	ToCtxStr_t;
676								signal 	CtxStr_Resp	: out	FromCtx_t;
677								signal 	CtxWin_Cmd	: in	ToCtxWin_t;
678								signal 	CtxWin_Resp : out	FromCtx_t;
679										Msg			: in	string		:= "") is
680		begin
681			ExpCtxRead(	Stream 		=> Stream,
682						BufStart 	=> BufStart_c(Stream),
683						WinSize		=> AutoWinSize_v,
684						Ptr			=> PtrStr_v(Stream),
685						Ringbuf		=> AutoRingbuf_v,
686						Overwrite	=> AutoOverwrite_v,
687						Wincnt		=> AutoWincnt_v,
688						Wincur		=> AutoWincur_v(Stream),
689						SamplesWin	=> SplsWinStr_v(Stream)(AutoWincur_v(Stream)),
690						Clk			=> Clk,
691						CtxStr_Cmd	=> CtxStr_Cmd,
692						CtxStr_Resp	=> CtxStr_Resp,
693						CtxWin_Cmd	=> CtxWin_Cmd,
694						CtxWin_Resp => CtxWin_Resp,
695						Msg			=> Msg);	
696		end procedure;
697		
698		procedure ExpCtxUpdateAuto(			Stream				: in	integer;
699											NextWin				: in	boolean		:= false;
700											IsTrig				: in	boolean		:= false;
701											WriteTs				: in	CheckTs_t	:= DontCheck;
702											Timstamp			: in	std_logic_vector(63 downto 0)	:= (others => 'X');
703								signal 		Clk					: in	std_logic;
704								signal 		CtxStr_Cmd			: in	ToCtxStr_t;
705								signal 		CtxStr_Resp			: out	FromCtx_t;
706								signal 		CtxWin_Cmd			: in	ToCtxWin_t;
707								signal 		CtxWin_Resp			: out	FromCtx_t;
708											Msg					: in	string		:= "") is
709		begin
710			while DmaCmdOpen = 0 loop
711				wait until rising_edge(Clk);
712			end loop;	
713			ExpCtxUpdate(	Stream				=> Stream,
714							TfSize				=> AutoAccessSize_v(Stream),
715							NextWin				=> NextWin,
716							IsTrig				=> IsTrig,
717							BufStart 			=> BufStart_c(Stream),
718							WinSize				=> AutoWinSize_v,
719							PtrBefore			=> PtrStr_v(Stream),
720							Ringbuf				=> AutoRingbuf_v,
721							Overwrite			=> AutoOverwrite_v,
722							Wincnt				=> AutoWincnt_v,
723							Wincur				=> AutoWincur_v(Stream),
724							SamplesWinBefore	=> SplsWinStr_v(Stream)(AutoWincur_v(Stream)),
725							WriteTs				=> WriteTs,
726							Timstamp			=> Timstamp,
727							PtrAfter			=> PtrStr_v(Stream),
728							Clk					=> Clk,
729							CtxStr_Cmd			=> CtxStr_Cmd,
730							CtxStr_Resp			=> CtxStr_Resp,
731							CtxWin_Cmd			=> CtxWin_Cmd,
732							CtxWin_Resp 		=> CtxWin_Resp,
733							Msg					=> Msg);	
734			SplsWinStr_v(Stream)(AutoWincur_v(Stream)) := work.psi_common_math_pkg.min(AutoWinSize_v/(StreamWidth_g(Stream)/8), SplsWinStr_v(Stream)(AutoWincur_v(Stream))+AutoAccessSize_v(Stream)/(StreamWidth_g(Stream)/8));
735			if NextWin then			
736				if AutoWincur_v(Stream) = AutoWincnt_v then
737					AutoWincur_v(Stream) := 0;
738				else
739					AutoWincur_v(Stream) := AutoWincur_v(Stream) + 1;
740				end if;
741			else
742				-- wraparound for ringbuffer case
743				if GetWindowOffset(Stream, PtrStr_v(Stream), AutoWincur_v, AutoWinSize_v) > AutoWinSize_v then
744					report "###ERROR### TB assertion, unhandled window crossing" severity error;
745				elsif GetWindowOffset(Stream, PtrStr_v(Stream), AutoWincur_v, AutoWinSize_v) = AutoWinSize_v then
746					if AutoRingbuf_v = '1' then
747						PtrStr_v(Stream) := BufStart_c(Stream);
748					end if;
749				end if;
750			end if;
751			
752		end procedure;
753		
754		procedure ExpCtxFullBurstAuto(		Stream				: in	integer;
755											NextWin				: in	boolean		:= false;
756											IsTrig				: in	boolean		:= false;
757											WriteTs				: in	CheckTs_t	:= DontCheck;
758											Timstamp			: in	std_logic_vector(63 downto 0)	:= (others => 'X');
759								signal 		Clk					: in	std_logic;
760								signal 		CtxStr_Cmd			: in	ToCtxStr_t;
761								signal 		CtxStr_Resp			: out	FromCtx_t;
762								signal 		CtxWin_Cmd			: in	ToCtxWin_t;
763								signal 		CtxWin_Resp			: out	FromCtx_t;
764											Msg					: in	string		:= "") is
765		begin
766			ExpCtxReadAuto(	Stream		=> Stream,
767							Clk			=> Clk,
768							CtxStr_Cmd	=> CtxStr_Cmd,
769							CtxStr_Resp	=> CtxStr_Resp,
770							CtxWin_Cmd	=> CtxWin_Cmd,
771							CtxWin_Resp => CtxWin_Resp,
772							Msg			=> Msg);
773			ExpCtxUpdateAuto(	Stream		=> Stream,
774								NextWin		=> NextWin,
775								IsTrig		=> IsTrig,
776								WriteTs		=> WriteTs,
777								Timstamp	=> Timstamp,
778								Clk			=> Clk,
779								CtxStr_Cmd	=> CtxStr_Cmd,
780								CtxStr_Resp	=> CtxStr_Resp,
781								CtxWin_Cmd	=> CtxWin_Cmd,
782								CtxWin_Resp	=> CtxWin_Resp,
783								Msg 		=> Msg);						
784		end procedure;
785		
786		procedure ConfigureAuto(	WinSize				: in	integer		:= 16#00100000#;
787									Ringbuf				: in	std_logic	:= '0';
788									Overwrite			: in	std_logic	:= '0';
789									Wincnt				: in	integer		:= 2;
790									Wincur				: in	integer		:= 0) is
791		begin
792			AutoWinSize_v 	:= WinSize;
793			AutoRingbuf_v 	:= Ringbuf;
794			AutoOverwrite_v	:= Overwrite;
795			AutoWincnt_v	:= Wincnt;
796			AutoWincur_v	:= (others => Wincur);
797		end procedure;
798		
799		procedure ExpectDmaCmdAuto(		Stream	: in 	integer;
800										MaxSize	: in 	integer;
801										ExeSize	: in	integer	:= -1;
802										NextWin	: in	boolean := false;
803								signal 	Clk		: in	std_logic;
804								signal 	Dma_Cmd	: in	DaqSm2DaqDma_Cmd_t;
805								signal 	Dma_Vld	: in	std_logic;
806										Msg		: in	string		:= "") is
807			variable ExeSize_v 			: integer;
808			variable NextWinNr_v		: integer;
809		begin
810			if ExeSize = -1 then
811				ExeSize_v := MaxSize;
812			else
813				ExeSize_v := ExeSize;
814			end if;
815			ExpectDmaCmd(	Stream 	=> Stream,
816							Address	=> PtrDma_v(Stream),
817							MaxSize	=> MaxSize,
818							Clk		=> Clk,
819							Dma_Cmd	=> Dma_Cmd,
820							Dma_Vld	=> Dma_Vld,
821							Msg		=> Msg);
822			if NextWin then			
823				if AutoWincur_v(Stream) = AutoWincnt_v then
824					NextWinNr_v := 0;
825				else
826					NextWinNr_v := AutoWincur_v(Stream) + 1;
827				end if;
828				PtrDma_v(Stream) := BufStart_c(Stream) + NextWinNr_v*AutoWinSize_v;
829			else
830				PtrDma_v(Stream) := PtrDma_v(Stream) + ExeSize_v;
831				-- wraparound for ringbuffer case
832				if GetWindowOffset(Stream, PtrDma_v(Stream), AutoWincur_v, AutoWinSize_v) > AutoWinSize_v then
833					report "###ERROR### TB assertion, unhandled window crossing" severity error;
834				elsif GetWindowOffset(Stream, PtrDma_v(Stream), AutoWincur_v, AutoWinSize_v) = AutoWinSize_v then
835					if AutoRingbuf_v = '1' then
836						PtrDma_v(Stream) := BufStart_c(Stream) + AutoWincur_v(Stream)*AutoWinSize_v;
837					end if;
838				end if;
839			end if;
840			AutoAccessSize_v(Stream) := ExeSize_v;
841		end procedure;
842		
843		procedure ApplyDmaRespAuto(		Stream 		: in	integer;
844										Trigger		: in	std_logic;
845										Delay		: in	time		:= 0 ns;
846								signal	Clk			: in	std_logic;
847								signal 	Dma_Resp		: out	DaqDma2DaqSm_Resp_t;
848								signal 	Dma_Resp_Vld	: out	std_logic;
849								signal 	Dma_Resp_Rdy	: in	std_logic;
850										Msg			: in	string		:= "") is
851		begin
852			while DmaCmdOpen = 0 loop
853				wait until rising_edge(Clk);
854			end loop;		
855			wait for 1 ps;
856			ApplyDmaResp(	Stream 			=> Stream,
857							Size 			=> AutoAccessSize_v(Stream),
858							Trigger			=> Trigger,
859							Delay			=> Delay,
860							Clk				=> Clk,
861							Dma_Resp 		=> Dma_Resp,
862							Dma_Resp_Vld	=> Dma_Resp_Vld,
863							Dma_Resp_Rdy	=> Dma_Resp_Rdy,
864							Msg				=> Msg);
865		end procedure;
866		
867		function GetWindowOffset(	Stream			: integer;
868									Ptr				: integer;
869									AutoWincur_v	: t_ainteger;
870									AutoWinSize_v	: integer) return integer is
871		begin
872			return Ptr - BufStart_c(Stream) - AutoWincur_v(Stream)*AutoWinSize_v;
873		end function;
874			
875	end;
