69										RdyDelay	: in	integer	:= 0;
70								signal 	Mem_DatData : in 	std_logic_vector;
71								signal 	Mem_DatVld 	: in 	std_logic;
72								signal 	Mem_DatRdy 	: out 	std_logic;
73								signal 	Clk			: in	std_logic;
74										Offset		: in	integer	:= 0;
75										Msg			: in	string := "");	
76	
77		procedure CheckMemCmd(			Address		: in	integer;
78										Bytes		: in	integer;
79										RdyDelay	: in	integer	:= 0;
80								signal	Mem_CmdAddr : in 	std_logic_vector;
81								signal	Mem_CmdSize : in 	std_logic_vector;
82								signal	Mem_CmdVld 	: in 	std_logic;
