172					for byte in 0 to 7 loop
173						if dw*8+byte >= Bytes then
174							Inp_Data(Stream).Data(8*(byte+1)-1 downto 8*byte)	<= (others => '0');
175						else
176							Inp_Data(Stream).Data(8*(byte+1)-1 downto 8*byte)	<= std_logic_vector(DataCnt_v);
177							DataCnt_v := DataCnt_v + 1;
178						end if;
