188							Inp_Data(Stream).Last <= '1';
189							Inp_Data(Stream).IsTo <= '1';					
190						end if;
191					end if;
192	
193					if Bytes-dw*8 > 8 then
194						Inp_Data(Stream).Bytes <= std_logic_vector(to_unsigned(8, 4));
