223				Mem_DatRdy <= '0';
224				for byte in 0 to 7 loop
225					if dw*8+byte >= Bytes then
226						-- nothing to compare
227					else
228						StdlvCompareInt (DataCnt_v, Mem_DatData(8*(byte+1)-1 downto 8*byte), "MEM_DATA: Wrong Data QW[" & to_string(dw) & "] Byte [" & to_string(byte) & "] - " & Msg, false); 
229						DataCnt_v := (DataCnt_v + 1) mod 256;
