240								signal	Mem_CmdVld 	: in 	std_logic;
241								signal	Mem_CmdRdy 	: out 	std_logic;
242								signal 	Clk			: in	std_logic;
243										Msg			: in	string := "") is
244		begin
245			if RdyDelay > 0 then
246				Mem_CmdRdy <= '0';
247			else
248				Mem_CmdRdy <= '1';
249			end if;
